// Domain Classification Logic
const domainMappings = {
  'finance': ['bloomberg', 'reuters', 'wsj', 'marketwatch', 'cnbc'],
  'sports': ['espn', 'bleacher', 'athletic', 'si', 'cbssports'],
  'technology': ['techcrunch', 'ars-technica', 'wired', 'theverge', 'engadget']
};

const items = $input.all();
const processedItems = [];

for (let item of items) {
  const feedUrl = item.json.meta.link || '';
  const title = item.json.title || '';
  const description = item.json.contentSnippet || item.json.description || '';

  // Determine domain based on feed URL and content
  let detectedDomain = 'general';
  for (const [domain, keywords] of Object.entries(domainMappings)) {
    if (keywords.some(keyword => 
      feedUrl.toLowerCase().includes(keyword) || 
      title.toLowerCase().includes(keyword) ||
      description.toLowerCase().includes(keyword)
    )) {
      detectedDomain = domain;
      break;
    }
  }

  // Content analysis for better classification
  const financeKeywords = ['stock', 'market', 'trading', 'economy', 'financial', 'investment', 'crypto', 'currency'];
  const sportsKeywords = ['game', 'match', 'player', 'team', 'score', 'season', 'championship', 'tournament'];
  const techKeywords = ['technology', 'software', 'ai', 'startup', 'app', 'digital', 'innovation', 'coding'];

  const contentLower = (title + ' ' + description).toLowerCase();

  if (detectedDomain === 'general') {
    if (financeKeywords.some(keyword => contentLower.includes(keyword))) {
      detectedDomain = 'finance';
    } else if (sportsKeywords.some(keyword => contentLower.includes(keyword))) {
      detectedDomain = 'sports';
    } else if (techKeywords.some(keyword => contentLower.includes(keyword))) {
      detectedDomain = 'technology';
    }
  }

  // Generate unique content ID
  const contentId = `content_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

  processedItems.push({
    json: {
      content_id: contentId,
      domain: detectedDomain,
      source_title: title,
      source_description: description,
      source_url: item.json.link,
      feed_url: feedUrl,
      pub_date: item.json.pubDate,
      priority: detectedDomain !== 'general' ? 'high' : 'medium',
      processing_timestamp: new Date().toISOString()
    }
  });
}

return processedItems;

// Style Parameter Randomization
const items = $input.all();
const configData = $('Load Domain Config').all();
const processedItems = [];

// Style variation parameters
const styleVariations = {
  tone: ['professional', 'conversational', 'analytical', 'engaging', 'authoritative'],
  complexity: ['beginner', 'intermediate', 'advanced'],
  structure: ['listicle', 'analysis', 'news', 'opinion', 'tutorial'],
  length: ['short', 'medium', 'long'], // 500-800, 800-1500, 1500-2500 words
  perspective: ['third-person', 'expert-analysis', 'industry-insider']
};

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const config = configData[i] ? configData[i].json : {};

  // Generate random style parameters within domain constraints
  const domainConstraints = config.style_parameters || {};
  const randomizedStyle = {};

  for (const [param, options] of Object.entries(styleVariations)) {
    const allowedOptions = domainConstraints[param] || options;
    randomizedStyle[param] = allowedOptions[Math.floor(Math.random() * allowedOptions.length)];
  }

  // Add randomization seed for reproducibility if needed
  randomizedStyle.seed = Math.random().toString(36).substr(2, 9);

  // Calculate content length based on style
  const lengthMapping = {
    'short': { min: 500, max: 800, target: 650 },
    'medium': { min: 800, max: 1500, target: 1150 },
    'long': { min: 1500, max: 2500, target: 2000 }
  };

  randomizedStyle.word_count = lengthMapping[randomizedStyle.length];

  processedItems.push({
    json: {
      ...item.json,
      domain_config: config,
      style_parameters: randomizedStyle,
      generation_prompt_template: config.prompt_template || 'default',
      quality_thresholds: config.quality_thresholds || { minimum_score: 75 }
    }
  });
}

return processedItems;

// Advanced Prompt Engineering
const items = $input.all();
const processedItems = [];

// Domain-specific prompt templates
const promptTemplates = {
  finance: `You are an expert financial analyst writing for a professional audience. 

Topic: {source_title}
Context: {source_description}

Write a {length} {structure} article with a {tone} tone that:
1. Provides accurate financial analysis based on the source material
2. Includes relevant market context and implications
3. Uses appropriate financial terminology
4. Maintains objectivity and professional standards
5. Targets {complexity} level readers

Style Guidelines:
- Use {perspective} perspective
- Target word count: {target_words} words
- Include actionable insights where appropriate
- Avoid speculative claims without supporting data

Please write the complete article now.`,

  sports: `You are a sports journalist writing engaging content for sports enthusiasts.

Topic: {source_title}
Context: {source_description}

Write a {length} {structure} article with a {tone} tone that:
1. Captures the excitement and drama of the sports topic
2. Provides relevant statistics and context
3. Appeals to {complexity} level sports fans
4. Uses appropriate sports terminology
5. Maintains accuracy in facts and figures

Style Guidelines:
- Use {perspective} perspective
- Target word count: {target_words} words
- Include player/team background where relevant
- Build narrative tension and engagement

Please write the complete article now.`,

  technology: `You are a technology expert writing for a tech-savvy audience.

Topic: {source_title}
Context: {source_description}

Write a {length} {structure} article with a {tone} tone that:
1. Explains technical concepts clearly for {complexity} readers
2. Provides industry context and implications
3. Uses appropriate technical terminology
4. Maintains accuracy in technical details
5. Discusses future implications or trends

Style Guidelines:
- Use {perspective} perspective
- Target word count: {target_words} words
- Include practical applications where relevant
- Balance technical depth with accessibility

Please write the complete article now.`,

  default: `You are a professional content writer creating high-quality articles.

Topic: {source_title}
Context: {source_description}

Write a {length} {structure} article with a {tone} tone that:
1. Thoroughly explores the topic based on the source material
2. Provides valuable insights and analysis
3. Targets {complexity} level readers
4. Maintains professional writing standards
5. Engages the audience effectively

Style Guidelines:
- Use {perspective} perspective
- Target word count: {target_words} words
- Include relevant examples and context
- Ensure content is well-structured and engaging

Please write the complete article now.`
};

for (const item of items) {
  const data = item.json;
  const domain = data.domain;
  const styleParams = data.style_parameters;

  // Select appropriate prompt template
  const template = promptTemplates[domain] || promptTemplates.default;

  // Replace placeholders with actual values
  let finalPrompt = template
    .replace(/{source_title}/g, data.source_title)
    .replace(/{source_description}/g, data.source_description)
    .replace(/{length}/g, styleParams.length)
    .replace(/{structure}/g, styleParams.structure)
    .replace(/{tone}/g, styleParams.tone)
    .replace(/{complexity}/g, styleParams.complexity)
    .replace(/{perspective}/g, styleParams.perspective)
    .replace(/{target_words}/g, styleParams.word_count.target);

  // Add domain-specific enhancements
  if (domain === 'finance') {
    finalPrompt += `\n\nAdditional Requirements:
- Include relevant financial metrics if available
- Mention regulatory implications if applicable
- Consider market timing and economic context
- Use precise financial terminology`;
  } else if (domain === 'sports') {
    finalPrompt += `\n\nAdditional Requirements:
- Include recent performance statistics if relevant
- Mention upcoming games/events if applicable
- Consider seasonal context and league standings
- Use sport-specific terminology accurately`;
  } else if (domain === 'technology') {
    finalPrompt += `\n\nAdditional Requirements:
- Include technical specifications if relevant
- Mention competitive landscape if applicable
- Consider adoption trends and market impact
- Use current industry terminology`;
  }

  processedItems.push({
    json: {
      ...data,
      generation_prompt: finalPrompt,
      prompt_version: '1.0',
      estimated_tokens: Math.ceil(finalPrompt.length / 3.5) // Rough token estimate
    }
  });
}

return processedItems;

// Regeneration Logic with Feedback Integration
const item = $input.first();
const qualityData = $('Quality Detection Agent').first();

// Extract feedback and suggestions
const feedback = qualityData.json.feedback || {};
const suggestions = qualityData.json.suggestions || [];
const qualityScore = qualityData.json.quality_score || 0;

// Generate improvement prompt based on feedback
let improvementInstructions = '\n\nIMPROVEMENT INSTRUCTIONS:\n';

if (feedback.readability && feedback.readability.score < 70) {
  improvementInstructions += '- Improve readability: Use shorter sentences and simpler vocabulary\n';
}

if (feedback.engagement && feedback.engagement.score < 70) {
  improvementInstructions += '- Increase engagement: Add more compelling examples and actionable insights\n';
}

if (feedback.structure && feedback.structure.score < 70) {
  improvementInstructions += '- Improve structure: Use better headers, bullet points, and logical flow\n';
}

if (feedback.accuracy && feedback.accuracy.score < 80) {
  improvementInstructions += '- Enhance accuracy: Verify facts and provide more specific details\n';
}

// Add specific suggestions
suggestions.forEach(suggestion => {
  improvementInstructions += `- ${suggestion}\n`;
});

// Modify the original prompt with improvements
const originalPrompt = item.json.generation_prompt;
const improvedPrompt = originalPrompt + improvementInstructions + 
  `\n\nPrevious attempt scored ${qualityScore}/100. Please address the above issues in your rewrite.`;

// Increment retry count
const retryCount = (item.json.retry_count || 0) + 1;

return [{
  json: {
    ...item.json,
    generation_prompt: improvedPrompt,
    retry_count: retryCount,
    previous_quality_score: qualityScore,
    improvement_feedback: feedback,
    regeneration_reason: 'quality_below_threshold'
  }
}];
